import{toRadians}from"./math.js";function disable(n,o){if(void 0!==n)return 0}function none(n,o){if(void 0!==n)return n+o}function createSnapToN(n){const t=2*Math.PI/n;return function(n,o){if(void 0!==n)return n=Math.floor((n+o)/t+.5)*t}}function createSnapToZero(n){const t=n||toRadians(5);return function(n,o){if(void 0!==n)return Math.abs(n+o)<=t?0:n+o}}export{disable,none,createSnapToN,createSnapToZero};